import { forwardRef, useImperativeHandle, useState } from "react";
import { formatBytes, useFileUpload } from "@/hooks/use-file-upload";
import { Button } from "@/components/ui/button";
import { HugeiconsIcon } from "@hugeicons/react";
import {
  AlertCircleIcon,
  Delete01Icon,
  Image01Icon,
  Upload01Icon,
} from "@hugeicons/core-free-icons";

interface ImageUploadProps {
  onFileChange?: (file: File | null) => void;
  onFilesChange?: (files: Array<File | string>) => void;
  maxSize?: number;
  accept?: string;
  disabled?: boolean;
  initialFile?: File | null;
  initialImage?: string;
  initialImages?: string[];
  multiple?: boolean;
}

export interface ImageUploadRef {
  clearFile: () => void;
  getFile: () => File | null;
}

const ImageUpload = forwardRef<ImageUploadRef, ImageUploadProps>(
  (
    {
      onFileChange,
      onFilesChange,
      maxSize = 10 * 1024 * 1024,
      accept = "image/svg+xml,image/png,image/jpeg,image/jpg,image/gif,image/webp",
      disabled = false,
      initialFile = null,
      initialImage = null,
      initialImages = [],
      multiple = false,
    },
    ref,
  ) => {
    const [initialImageCleared, setInitialImageCleared] = useState(false);

    const [
      { files, isDragging, errors },
      {
        handleDragEnter,
        handleDragLeave,
        handleDragOver,
        handleDrop,
        openFileDialog,
        removeFile,
        getInputProps,
      },
    ] = useFileUpload({
      maxSize,
      accept,
      multiple,
      initialFiles: initialFile
        ? [
            {
              name: initialFile.name,
              size: initialFile.size,
              type: initialFile.type,
              url: "",
              id: `${initialFile.name}-${Date.now()}`,
            },
          ]
        : initialImages?.length
          ? initialImages.map((url, index) => ({
              name: url.split("/").pop() || `image-${index}`,
              size: 0,
              type: "image/*",
              url,
              id: `${url}-${index}`,
            }))
          : [],
      onFilesChange: (newFiles) => {
        if (multiple) {
          const mixedFiles = newFiles.map((f) => {
            if (f.file instanceof File) return f.file;
            // If it's metadata, try to get the url (which we stored as preview too)
            return (f.file as any).url || f.preview || "";
          });
          onFilesChange?.(mixedFiles);

          const filesOnly = newFiles
            .map((f) => (f.file instanceof File ? f.file : null))
            .filter((f): f is File => !!f);
          if (filesOnly.length) onFileChange?.(filesOnly[0]);
        } else {
          const filesOnly = newFiles
            .map((f) => (f.file instanceof File ? f.file : null))
            .filter((f): f is File => !!f);
          const file = filesOnly.length ? filesOnly[0] : null;
          onFileChange?.(file);
        }
      },
    });

    useImperativeHandle(ref, () => ({
      clearFile: () => {
        if (files.length > 0) {
          removeFile(files[0].id);
        } else if (initialImage) {
          setInitialImageCleared(true);
          onFileChange?.(null);
        }
      },
      getFile: (): File | null => {
        if (!files.length) return null;
        const file = files[0].file;
        return file instanceof File ? file : null;
      },
    }));

    const file = files[0];
    const previewUrl = multiple
      ? null
      : file?.preview || (initialImageCleared ? null : initialImage) || null;
    const maxSizeMB = Math.round(maxSize / (1024 * 1024));

    return (
      <div className="flex flex-col gap-2">
        <div className="relative">
          {/* Drop area */}
          <div
            role="button"
            onClick={disabled ? undefined : openFileDialog}
            onDragEnter={disabled ? undefined : handleDragEnter}
            onDragLeave={disabled ? undefined : handleDragLeave}
            onDragOver={disabled ? undefined : handleDragOver}
            onDrop={disabled ? undefined : handleDrop}
            data-dragging={isDragging || undefined}
            className={`hover:bg-accent/50 data-[dragging=true]:bg-accent/50 relative flex min-h-46 flex-col items-center justify-center overflow-hidden border-2 border-dashed border-main-600 rounded-[15px]  p-4 transition-colors has-disabled:pointer-events-none has-disabled:opacity-50 ${
              disabled ? "pointer-events-none opacity-50" : ""
            }`}
          >
            <input
              {...getInputProps()}
              className="sr-only"
              aria-label="Upload image file"
              disabled={
                disabled ||
                (!multiple &&
                  (Boolean(file) ||
                    (Boolean(initialImage) && !initialImageCleared)))
              }
              accept={accept}
              multiple={multiple}
            />

            {previewUrl ? (
              <div className="absolute inset-0 flex items-center justify-center p-4">
                <img
                  src={previewUrl}
                  alt={file?.file?.name || initialImage || "Uploaded image"}
                  className="mx-auto max-h-46 rounded object-contain"
                />
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center px-4 py-3 text-center">
                <HugeiconsIcon
                  icon={Upload01Icon}
                  className="size-9 text-main-600"
                />
                <p className="my-1.5 text-sm font-medium">
                  {file || (initialImage && !initialImageCleared)
                    ? multiple
                      ? "Images selected"
                      : "Image selected"
                    : multiple
                      ? "Drop your images here"
                      : "Drop image here"}
                </p>
                <p className="text-muted-foreground text-xs">
                  {file || (initialImage && !initialImageCleared)
                    ? multiple
                      ? "Click to upload more"
                      : "Click to change"
                    : `SVG, PNG, JPG or GIF (max. ${maxSizeMB}MB)`}
                </p>
              </div>
            )}
          </div>

          {/* Remove button overlay for preview */}
          {previewUrl && !disabled && (
            <div className="absolute top-4 right-4">
              <button
                type="button"
                className="focus-visible:border-ring focus-visible:ring-ring/50 z-50 flex size-8 cursor-pointer items-center justify-center rounded-full bg-black/60 text-white transition-[color,box-shadow] outline-none hover:bg-black/80 focus-visible:ring-[3px]"
                onClick={() => {
                  if (file) {
                    removeFile(file.id);
                  } else if (initialImage) {
                    // Clear the initial image and allow new uploads
                    setInitialImageCleared(true);
                    onFileChange?.(null);
                  }
                }}
                aria-label={"Remove image"}
              >
                <HugeiconsIcon
                  icon={Delete01Icon}
                  className="size-4"
                  aria-hidden="true"
                />
              </button>
            </div>
          )}
        </div>

        {errors.length > 0 && (
          <div
            className="text-destructive flex items-center gap-1 text-xs"
            role="alert"
          >
            <HugeiconsIcon icon={AlertCircleIcon} className="size-3 shrink-0" />
            <span>{errors[0]}</span>
          </div>
        )}

        {multiple && files.length > 0 && (
          <div className="grid xs:grid-cols-2 lg:grid-cols-3 gap-3 mt-3">
            {files.map((f) => (
              <div key={f.id} className="relative rounded-lg border p-2">
                <img
                  src={f.preview || ""}
                  alt={f.file?.name || "Uploaded image"}
                  className="w-full h-24 rounded object-cover"
                />
                <div className="mt-2 flex items-center justify-between gap-2">
                  <p className="truncate text-[12px] font-medium">
                    {f.file instanceof File ? f.file.name : f.file?.name}
                  </p>
                  <span className="text-muted-foreground text-[11px]">
                    {formatBytes(
                      f.file instanceof File ? f.file.size : f.file?.size || 0,
                    )}
                  </span>
                </div>
                {!disabled && (
                  <Button
                    size="icon"
                    variant="destructive"
                    type="button"
                    className="absolute top-2 right-2 size-7"
                    onClick={() => removeFile(f.id)}
                    aria-label="Remove image"
                  >
                    <HugeiconsIcon
                      icon={Delete01Icon}
                      className="size-4"
                      aria-hidden="true"
                    />
                  </Button>
                )}
              </div>
            ))}
          </div>
        )}

        {!multiple && file && !previewUrl && (
          <div className="space-y-2">
            <div
              key={file.id}
              className="flex items-center justify-between gap-2 rounded-xl border px-4 py-2"
            >
              <div className="flex items-center gap-3 overflow-hidden">
                <HugeiconsIcon
                  icon={Image01Icon}
                  className="size-4 shrink-0 opacity-60"
                  aria-hidden="true"
                />
                <div className="min-w-0">
                  <p className="truncate text-[13px] font-medium">
                    {file.file instanceof File
                      ? file.file.name
                      : file.file.name}
                  </p>
                  <p className="text-muted-foreground text-xs">
                    {formatBytes(
                      file.file instanceof File
                        ? file.file.size
                        : file.file.size,
                    )}
                  </p>
                </div>
              </div>

              {!disabled && (
                <Button
                  size="icon"
                  variant="ghost"
                  type="button"
                  className="text-muted-foreground/80 hover:text-foreground -me-2 size-8 hover:bg-transparent"
                  onClick={() => removeFile(file.id)}
                  aria-label="Remove image"
                >
                  <HugeiconsIcon
                    icon={Delete01Icon}
                    className="size-4"
                    aria-hidden="true"
                  />
                </Button>
              )}
            </div>
          </div>
        )}
      </div>
    );
  },
);

ImageUpload.displayName = "ImageUpload";

export default ImageUpload;
export type { ImageUploadProps };

'use client'

import { useCallback, useRef, useState } from 'react'
import type { ChangeEvent, DragEvent, InputHTMLAttributes } from 'react'
import type React from 'react'

export type FileMetadata = {
  name: string
  size: number
  type: string
  url: string
  id: string
}

export type FileWithPreview = {
  file: File | FileMetadata
  id: string
  preview?: string
}

export type FileUploadOptions = {
  maxFiles?: number // Only used when multiple is true, defaults to Infinity
  maxSize?: number // in bytes
  accept?: string
  multiple?: boolean // Defaults to false
  initialFiles?: Array<FileMetadata>
  onFilesChange?: (files: Array<FileWithPreview>) => void // Callback when files change
  onFilesAdded?: (addedFiles: Array<FileWithPreview>) => void // Callback when new files are added
}

export type FileUploadState = {
  files: Array<FileWithPreview>
  isDragging: boolean
  errors: Array<string>
}

export type FileUploadActions = {
  addFiles: (files: FileList | Array<File>) => void
  removeFile: (id: string) => void
  clearFiles: () => void
  clearErrors: () => void
  handleDragEnter: (e: DragEvent<HTMLElement>) => void
  handleDragLeave: (e: DragEvent<HTMLElement>) => void
  handleDragOver: (e: DragEvent<HTMLElement>) => void
  handleDrop: (e: DragEvent<HTMLElement>) => void
  handleFileChange: (e: ChangeEvent<HTMLInputElement>) => void
  openFileDialog: () => void
  getInputProps: (
    props?: InputHTMLAttributes<HTMLInputElement>,
  ) => InputHTMLAttributes<HTMLInputElement> & {
    ref: React.Ref<HTMLInputElement>
  }
}

export const useFileUpload = (
  options: FileUploadOptions = {},
): [FileUploadState, FileUploadActions] => {
  const {
    maxFiles = Infinity,
    maxSize = Infinity,
    accept = '*',
    multiple = false,
    initialFiles = [],
    onFilesChange,
    onFilesAdded,
  } = options

  const [state, setState] = useState<FileUploadState>({
    files: initialFiles.map((file) => ({
      file,
      id: file.id,
      preview: file.url,
    })),
    isDragging: false,
    errors: [],
  })

  const inputRef = useRef<HTMLInputElement>(null)

  const validateFile = useCallback(
    (file: File | FileMetadata): string | null => {
      if (file instanceof File) {
        if (file.size > maxSize) {
          return `File "${file.name}" exceeds the maximum size of ${formatBytes(maxSize)}.`
        }
      } else {
        if (file.size > maxSize) {
          return `File "${file.name}" exceeds the maximum size of ${formatBytes(maxSize)}.`
        }
      }

      if (accept !== '*') {
        const acceptedTypes = accept.split(',').map((type) => type.trim())
        const fileType = file instanceof File ? file.type || '' : file.type
        const fileExtension = `.${file instanceof File ? file.name.split('.').pop() : file.name.split('.').pop()}`

        const isAccepted = acceptedTypes.some((type) => {
          if (type.startsWith('.')) {
            return fileExtension.toLowerCase() === type.toLowerCase()
          }
          if (type.endsWith('/*')) {
            const baseType = type.split('/')[0]
            return fileType.startsWith(`${baseType}/`)
          }
          return fileType === type
        })

        if (!isAccepted) {
          return `File "${file instanceof File ? file.name : file.name}" is not an accepted file type.`
        }
      }

      return null
    },
    [accept, maxSize],
  )

  const createPreview = useCallback(
    (file: File | FileMetadata): string | undefined => {
      if (file instanceof File) {
        return URL.createObjectURL(file)
      }
      return file.url
    },
    [],
  )

  const generateUniqueId = useCallback((file: File | FileMetadata): string => {
    if (file instanceof File) {
      return `${file.name}-${Date.now()}-${Math.random().toString(36).substring(2, 9)}`
    }
    return file.id
  }, [])

  const clearFiles = useCallback(() => {
    setState((prev) => {
      // Clean up object URLs
      prev.files.forEach((file) => {
        if (
          file.preview &&
          file.file instanceof File &&
          file.file.type.startsWith('image/')
        ) {
          URL.revokeObjectURL(file.preview)
        }
      })

      if (inputRef.current) {
        inputRef.current.value = ''
      }

      const newState = {
        ...prev,
        files: [],
        errors: [],
      }

      onFilesChange?.(newState.files)
      return newState
    })
  }, [onFilesChange])

  const addFiles = useCallback(
    (newFiles: FileList | Array<File>) => {
      if (!newFiles || newFiles.length === 0) return

      const newFilesArray = Array.from(newFiles)
      const errors: Array<string> = []

      // Clear existing errors when new files are uploaded
      setState((prev) => ({ ...prev, errors: [] }))

      // In single file mode, clear existing files first
      if (!multiple) {
        clearFiles()
      }

      // Check if adding these files would exceed maxFiles (only in multiple mode)
      if (
        multiple &&
        maxFiles !== Infinity &&
        state.files.length + newFilesArray.length > maxFiles
      ) {
        errors.push(`You can only upload a maximum of ${maxFiles} files.`)
        setState((prev) => ({ ...prev, errors }))
        return
      }

      const validFiles: Array<FileWithPreview> = []

      newFilesArray.forEach((file) => {
        // Only check for duplicates if multiple files are allowed
        if (multiple) {
          const isDuplicate = state.files.some(
            (existingFile) =>
              existingFile.file.name === file.name &&
              existingFile.file.size === file.size,
          )

          // Skip duplicate files silently
          if (isDuplicate) {
            return
          }
        }

        // Check file size
        if (file.size > maxSize) {
          errors.push(
            multiple
              ? `Some files exceed the maximum size of ${formatBytes(maxSize)}.`
              : `File exceeds the maximum size of ${formatBytes(maxSize)}.`,
          )
          return
        }

        const error = validateFile(file)
        if (error) {
          errors.push(error)
        } else {
          validFiles.push({
            file,
            id: generateUniqueId(file),
            preview: createPreview(file),
          })
        }
      })

      // Only update state if we have valid files to add
      if (validFiles.length > 0) {
        // Call the onFilesAdded callback with the newly added valid files
        onFilesAdded?.(validFiles)

        setState((prev) => {
          const newFiles = !multiple
            ? validFiles
            : [...prev.files, ...validFiles]
          onFilesChange?.(newFiles)
          return {
            ...prev,
            files: newFiles,
            errors,
          }
        })
      } else if (errors.length > 0) {
        setState((prev) => ({
          ...prev,
          errors,
        }))
      }

      // Reset input value after handling files
      if (inputRef.current) {
        inputRef.current.value = ''
      }
    },
    [
      state.files,
      maxFiles,
      multiple,
      maxSize,
      validateFile,
      createPreview,
      generateUniqueId,
      clearFiles,
      onFilesChange,
      onFilesAdded,
    ],
  )

  const removeFile = useCallback(
    (id: string) => {
      setState((prev) => {
        const fileToRemove = prev.files.find((file) => file.id === id)
        if (
          fileToRemove &&
          fileToRemove.preview &&
          fileToRemove.file instanceof File &&
          fileToRemove.file.type.startsWith('image/')
        ) {
          URL.revokeObjectURL(fileToRemove.preview)
        }

        const newFiles = prev.files.filter((file) => file.id !== id)
        onFilesChange?.(newFiles)

        return {
          ...prev,
          files: newFiles,
          errors: [],
        }
      })
    },
    [onFilesChange],
  )

  const clearErrors = useCallback(() => {
    setState((prev) => ({
      ...prev,
      errors: [],
    }))
  }, [])

  const handleDragEnter = useCallback((e: DragEvent<HTMLElement>) => {
    e.preventDefault()
    e.stopPropagation()
    setState((prev) => ({ ...prev, isDragging: true }))
  }, [])

  const handleDragLeave = useCallback((e: DragEvent<HTMLElement>) => {
    e.preventDefault()
    e.stopPropagation()

    if (e.currentTarget.contains(e.relatedTarget as Node)) {
      return
    }

    setState((prev) => ({ ...prev, isDragging: false }))
  }, [])

  const handleDragOver = useCallback((e: DragEvent<HTMLElement>) => {
    e.preventDefault()
    e.stopPropagation()
  }, [])

  const handleDrop = useCallback(
    (e: DragEvent<HTMLElement>) => {
      e.preventDefault()
      e.stopPropagation()
      setState((prev) => ({ ...prev, isDragging: false }))

      // Don't process files if the input is disabled
      if (inputRef.current?.disabled) {
        return
      }

      if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
        // In single file mode, only use the first file
        if (!multiple) {
          const file = e.dataTransfer.files[0]
          addFiles([file])
        } else {
          addFiles(e.dataTransfer.files)
        }
      }
    },
    [addFiles, multiple],
  )

  const handleFileChange = useCallback(
    (e: ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files.length > 0) {
        addFiles(e.target.files)
      }
    },
    [addFiles],
  )

  const openFileDialog = useCallback(() => {
    if (inputRef.current) {
      inputRef.current.click()
    }
  }, [])

  const getInputProps = useCallback(
    (props: InputHTMLAttributes<HTMLInputElement> = {}) => {
      return {
        ...props,
        type: 'file' as const,
        onChange: handleFileChange,
        accept: props.accept || accept,
        multiple: props.multiple !== undefined ? props.multiple : multiple,
        ref: inputRef,
      }
    },
    [accept, multiple, handleFileChange],
  )

  return [
    state,
    {
      addFiles,
      removeFile,
      clearFiles,
      clearErrors,
      handleDragEnter,
      handleDragLeave,
      handleDragOver,
      handleDrop,
      handleFileChange,
      openFileDialog,
      getInputProps,
    },
  ]
}

// Helper function to format bytes to human-readable format
export const formatBytes = (bytes: number, decimals = 2): string => {
  if (bytes === 0) return '0 Bytes'

  const k = 1024
  const dm = decimals < 0 ? 0 : decimals
  const sizes = ['Bytes', 'KB', 'MB', 'GB', 'TB', 'PB', 'EB', 'ZB', 'YB']

  const i = Math.floor(Math.log(bytes) / Math.log(k))

  return Number.parseFloat((bytes / Math.pow(k, i)).toFixed(dm)) + sizes[i]
}
